// Garantir que o output exista e seja string
const output = $json.output ?? "";

// Sanitizar quebra de linha, espaços extras, unicode estranho etc.
const clean = output
  .toString()
  .trim()
  .replace(/\s+/g, ""); // REMOVE espaços, quebras e tabs indesejados

// Retornar sempre o campo "output" limpo
return [{ output: clean }];
